      }
    }
  }

  const result: Cell[] = [];
  for (const [key, count] of neighborCounts) {
    const isAlive = liveSet.has(key);
    if (count === 3 || (count === 2 && isAlive)) {
      const [x, y] = key.split(",").map(Number);
      result.push([x, y]);
    }
  }
  return result;
}
